// --- REPORTE GENERAL ---
const generarPDFGeneralEmpleado = async () => {
  if (!empleadoSeleccionadoGeneral.value) {
    Swal.fire('Aviso', 'Por favor seleccione un empleado primero.', 'warning');
    return;
  }

  isLoadingGeneralPDF.value = true;

  try {
    const empId = empleadoSeleccionadoGeneral.value;
    const empleadoInfo = empleados.value.find(e => e.id === empId);

    const [resContratos, resVacaciones, resFaltas, resNotas, resDocs] = await Promise.all([
      axios.get(`http://localhost:3007/api/empleados/${empId}/contratos`).catch(() => ({ data: [] })),
      axios.get(`http://localhost:3007/api/vacaciones/empleado/${empId}`).catch(() => ({ data: [] })),
      axios.get(`http://localhost:3007/api/faltas/empleado/${empId}`).catch(() => ({ data: [] })),
      axios.get(`http://localhost:3007/api/notas/empleado/${empId}`).catch(() => ({ data: [] })),
      axios.get(`http://localhost:3007/api/documentos/empleado/${empId}`).catch(() => ({ data: [] }))
    ]);

    const contratosData = resContratos.data || [];
    const vacacionesData = resVacaciones.data || [];
    const faltasData = resFaltas.data || [];
    const notasData = resNotas.data || [];
    const docsData = resDocs.data || [];

    const ticketsData = tickets.value.filter(t => t.empleado_id === empId || t.asignado_empleado_id === empId);
    const incidenciasData = incidenciasDatos.value.filter(i => i.empleado_id === empId);

    const doc = new jsPDF();
    const pageHeight = doc.internal.pageSize.height;

    const imgLogo = new Image();
    imgLogo.src = 'http://localhost:3007/uploads/Logo/Logo.png';
    doc.addImage(imgLogo, 'PNG', 14, 10, 30, 30);

    doc.setFontSize(22);
    doc.setTextColor(30, 58, 138);
    doc.text('REPORTE GENERAL DE EMPLEADO', 50, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Generado: ${new Date().toLocaleDateString('es-HN')} ${new Date().toLocaleTimeString('es-HN')}`, 50, 28);

    doc.setDrawColor(226, 232, 240);
    doc.setLineWidth(0.5);
    doc.line(14, 45, 196, 45);

    doc.setFontSize(12);
    doc.setTextColor(15, 23, 42);
    doc.setFont('helvetica', 'bold');
    doc.text('Datos del Empleado:', 14, 55);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text(`Nombre: ${empleadoInfo.nombre} ${empleadoInfo.apellido}`, 14, 62);
    doc.text(`Identidad: ${empleadoInfo.identidad}`, 14, 68);
    doc.text(`Puesto: ${empleadoInfo.puesto_nombre || 'N/A'}`, 14, 74);
    doc.text(`Departamento: ${empleadoInfo.departamento_nombre || 'N/A'}`, 14, 80);
    doc.text(`Estado: ${empleadoInfo.estado || 'Activo'}`, 14, 86);

    let currentY = 100;

    const checkPageBreak = (neededSpace = 30) => {
      if (currentY + neededSpace >= pageHeight - 20) {
        doc.addPage();
        currentY = 20;
      }
    };

    // 1. CONTRATOS
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('1. Historial de Contratos', 14, currentY);
    currentY += 8;

    if (contratosData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Tipo', 'Salario', 'Inicio', 'Fin', 'Estado']],
        body: contratosData.map(c => [
          c.tipo_contrato, 
          `L. ${c.salario}`, 
          new Date(c.fecha_inicio).toLocaleDateString('es-HN'),
          c.fecha_fin ? new Date(c.fecha_fin).toLocaleDateString('es-HN') : 'Indefinido',
          c.estado
        ]),
        theme: 'grid',
        headStyles: { fillColor: [59, 130, 246] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay contratos registrados.', 14, currentY);
      currentY += 15;
    }

    // 2. VACACIONES
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('2. Historial de Vacaciones', 14, currentY);
    currentY += 8;

    if (vacacionesData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Inicio', 'Fin', 'Días', 'Estado']],
        body: vacacionesData.map(v => [
          new Date(v.fecha_inicio).toLocaleDateString('es-HN'),
          new Date(v.fecha_fin).toLocaleDateString('es-HN'),
          v.dias_solicitados.toString(),
          v.estado
        ]),
        theme: 'grid',
        headStyles: { fillColor: [16, 185, 129] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay vacaciones registradas.', 14, currentY);
      currentY += 15;
    }

    // 3. FALTAS
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('3. Historial de Faltas', 14, currentY);
    currentY += 8;

    if (faltasData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Fecha', 'Tipo', 'Motivo']],
        body: faltasData.map(f => [
          new Date(f.fecha).toLocaleDateString('es-HN'),
          f.tipo,
          f.motivo || 'N/A'
        ]),
        theme: 'grid',
        headStyles: { fillColor: [245, 158, 11] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay faltas registradas.', 14, currentY);
      currentY += 15;
    }

    // 4. NOTAS
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('4. Historial de Notas', 14, currentY);
    currentY += 8;

    if (notasData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Fecha', 'Nota']],
        body: notasData.map(n => [
          new Date(n.fecha_creacion).toLocaleDateString('es-HN'),
          n.contenido
        ]),
        theme: 'grid',
        headStyles: { fillColor: [99, 102, 241] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay notas registradas.', 14, currentY);
      currentY += 15;
    }

    // 5. DOCUMENTOS
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('5. Historial de Documentos', 14, currentY);
    currentY += 8;

    if (docsData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Tipo/Nombre', 'Fecha Subida']],
        body: docsData.map(d => [
          d.nombre || d.tipo || 'Documento',
          new Date(d.fecha_subida || d.fecha_creacion).toLocaleDateString('es-HN')
        ]),
        theme: 'grid',
        headStyles: { fillColor: [71, 85, 105] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay documentos registrados.', 14, currentY);
      currentY += 15;
    }

    // 6. INCIDENCIAS
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('6. Reportes de Incidencia', 14, currentY);
    currentY += 8;

    if (incidenciasData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Fecha', 'Gravedad', 'Categoría', 'Estado']],
        body: incidenciasData.map(i => [
          new Date(i.fecha_incidencia).toLocaleDateString('es-HN'),
          i.gravedad,
          i.categoria_nombre,
          i.estado
        ]),
        theme: 'grid',
        headStyles: { fillColor: [225, 29, 72] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay incidencias registradas.', 14, currentY);
      currentY += 15;
    }

    // 7. TICKETS
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setTextColor(30, 58, 138);
    doc.setFont('helvetica', 'bold');
    doc.text('7. Tickets de Soporte', 14, currentY);
    currentY += 8;

    if (ticketsData.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['ID', 'Prioridad', 'Categoría', 'Estado']],
        body: ticketsData.map(t => [
          `#${t.id}`,
          t.prioridad,
          t.Categoria,
          t.estado
        ]),
        theme: 'grid',
        headStyles: { fillColor: [217, 119, 6] },
        styles: { fontSize: 8 }
      });
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(9);
      doc.setTextColor(100);
      doc.text('No hay tickets registrados.', 14, currentY);
      currentY += 15;
    }

    // Paginación
    const pageCount = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(8);
      doc.setTextColor(150);
      doc.text(`Página ${i} de ${pageCount}`, doc.internal.pageSize.width / 2, pageHeight - 10, { align: 'center' });
    }

    doc.save(`Reporte_General_${empleadoInfo.nombre}_${empleadoInfo.apellido}.pdf`);
  } catch (error) {
    console.error("Error al generar PDF General:", error);
    Swal.fire('Error', 'Hubo un error al generar el PDF consolidado', 'error');
  } finally {
    isLoadingGeneralPDF.value = false;
  }
}
